import { useEffect, useId, useMemo, useRef, useState } from 'react';

import useClickOutside from '../helpers/UseClickOutside.js';

import './Select.css';

function Select({ ariaLabel, className = '', clearable = false, disabled = false, id, label, name, onChange, options, placeholder = 'Select…', searchable = true, value }) {
  const generatedId = useId();
  const inputId = id ?? generatedId;
  const listboxId = `${inputId}-listbox`;

  const wrapperRef = useRef(null);
  const inputRef = useRef(null);

  const [query, setQuery] = useState(value?.label ?? '');
  const [open, setOpen] = useState(false);
  const [hasTypedSinceOpen, setHasTypedSinceOpen] = useState(false);
  const [highlightedIndex, setHighlightedIndex] = useState(-1);

  useEffect(() => {
    setQuery(value?.label ?? '');
  }, [value]);

  const filteredOptions = useMemo(() => {
    if (!hasTypedSinceOpen || !query) return options;
    const lowerQuery = query.toLowerCase();
    return options.filter(option => option.label.toLowerCase().includes(lowerQuery));
  }, [hasTypedSinceOpen, options, query]);

  useEffect(() => {
    if (!open || highlightedIndex < 0) return;
    const optionEl = document.getElementById(`${listboxId}-option-${highlightedIndex}`);
    optionEl?.scrollIntoView({ block: 'nearest' });
  }, [open, highlightedIndex, listboxId]);

  const closePopup = () => {
    setOpen(false);
    setHasTypedSinceOpen(false);
    setQuery(value?.label ?? '');
  };

  useClickOutside(wrapperRef, closePopup, open);

  const openPopup = () => {
    if (disabled) return;
    setOpen(true);
    setHasTypedSinceOpen(false);
    const currentIndex = value ? options.findIndex(option => option.value === value.value) : -1;
    setHighlightedIndex(currentIndex >= 0 ? currentIndex : 0);
  };

  const selectOption = option => {
    onChange(option);
    setQuery(option.label);
    setOpen(false);
    setHasTypedSinceOpen(false);
  };

  const handleInputChange = event => {
    setQuery(event.target.value);
    setHasTypedSinceOpen(true);
    setOpen(true);
    setHighlightedIndex(0);
  };

  const handleClear = () => {
    onChange(null);
    setQuery('');
    inputRef.current?.focus();
  };

  const handleKeyDown = event => {
    if (event.key === 'ArrowDown') {
      event.preventDefault();
      if (!open) {
        openPopup();
        return;
      }
      setHighlightedIndex(current => Math.min(current + 1, filteredOptions.length - 1));
    } else if (event.key === 'ArrowUp') {
      event.preventDefault();
      if (!open) {
        openPopup();
        return;
      }
      setHighlightedIndex(current => Math.max(current - 1, 0));
    } else if (event.key === 'Home') {
      if (open) {
        event.preventDefault();
        setHighlightedIndex(0);
      }
    } else if (event.key === 'End') {
      if (open) {
        event.preventDefault();
        setHighlightedIndex(filteredOptions.length - 1);
      }
    } else if (event.key === 'Enter') {
      if (open && highlightedIndex >= 0 && filteredOptions[highlightedIndex]) {
        event.preventDefault();
        selectOption(filteredOptions[highlightedIndex]);
      }
    } else if (event.key === 'Escape') {
      if (open) {
        event.preventDefault();
        closePopup();
      }
    }
  };

  const activeOptionId = open && highlightedIndex >= 0 && filteredOptions[highlightedIndex] ? `${listboxId}-option-${highlightedIndex}` : undefined;

  return (
    <div className={`un_select ${className}`.trim()} ref={wrapperRef}>
      {label && <label htmlFor={inputId}>{label}</label>}
      <div className="un_select_control">
        <input
          aria-activedescendant={activeOptionId}
          aria-autocomplete="list"
          aria-controls={listboxId}
          aria-expanded={open}
          aria-haspopup="listbox"
          aria-label={label ? undefined : ariaLabel}
          disabled={disabled}
          id={inputId}
          onChange={searchable ? handleInputChange : undefined}
          onClick={openPopup}
          onFocus={openPopup}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          readOnly={!searchable}
          ref={inputRef}
          role="combobox"
          type="text"
          value={query}
        />
        {clearable && value && (
          <button aria-label="Clear selection" className="un_select_clear" disabled={disabled} onClick={handleClear} type="button">
            ×
          </button>
        )}
        <span aria-hidden="true" className="un_select_chevron" />
      </div>
      {name && <input name={name} type="hidden" value={value?.value ?? ''} />}
      {open && (
        <ul className="un_select_listbox" id={listboxId} role="listbox">
          {filteredOptions.map((option, index) => (
            <li
              aria-selected={option.value === value?.value}
              className={`un_select_option${index === highlightedIndex ? ' highlighted' : ''}`}
              id={`${listboxId}-option-${index}`}
              key={option.value}
              onMouseDown={event => {
                event.preventDefault();
                selectOption(option);
              }}
              onMouseEnter={() => setHighlightedIndex(index)}
              role="option"
            >
              {option.label}
            </li>
          ))}
          {filteredOptions.length === 0 && (
            <li aria-disabled="true" className="un_select_empty">
              No matches
            </li>
          )}
        </ul>
      )}
    </div>
  );
}

export default Select;
